import SummaryProduct from "../../../components/checkout page/summary-product";

const Authentication = () => {
  return (
    <Layout>
      <GridLayout>
        <div className="container">
        <AuthenticationForm />
        <SummaryProduct />

        </div>

      </GridLayout>
    </Layout>
  );
};

export default Authentication;
